36	const payloadSchema = z.object({
37	  documentId: z.string().uuid().optional(),
38	  sourceOutlineId: z.string().uuid().optional(),
39	  claimIds: z.array(z.string().uuid()).optional(),
40	  relationshipScope: z.enum(['single_source', 'cross_source']).default('single_source'),
41	});
