43	const DEFAULT_MACRO_RELATIONSHIP_NEAR_DUPLICATE_DISTANCE = 0.08;
44	
45	type SupportClaim = {
46	  id: string;
47	  summary: string;
48	  claimType: string;
49	  claimKind: string | null;
50	  claimKindConfidence: number | null;
51	  claimKindReviewStatus: string | null;
