61	};
62	
63	function sha256(text: string): string {
64	  return createHash('sha256').update(text, 'utf8').digest('hex');
65	}
66	
67	function buildContextPackInsert(plan: OraclePromptPlan) {
68	  return {
69	    taskType: plan.taskType,
70	    routeId: plan.routeId,
71	    promptVersion: plan.promptVersion,
72	    schemaVersion: plan.schemaVersion ?? null,
73	    stablePrefixHash: plan.metadata.stablePrefixHash,
74	    semiStableContextHash: plan.metadata.semiStableContextHash ?? null,
75	    retrievedContextHash: plan.metadata.retrievedContextHash ?? null,
76	    dynamicInputHash: plan.metadata.dynamicInputHash,
77	    toolSchemaHash: plan.metadata.toolSchemaHash ?? null,
78	    outputSchemaHash: plan.metadata.outputSchemaHash ?? null,
79	    blocksJson: plan.blocks.map((b) => ({
80	      id: b.id,
81	      label: b.label,
82	      kind: b.kind,
83	      hash: b.hash,
84	      tokenEstimate: b.tokenEstimate ?? null,
85	      cacheEligible: b.cacheEligible,
86	      reasonIncluded: b.reasonIncluded,
87	    })),
88	    includedClaimIds: plan.metadata.includedClaimIds ?? null,
89	  };
90	}
91	
92	function formatClaimsForPrompt(rows: SupportClaim[]): string {
93	  return rows
94	    .map(
95	      (claim, index) =>
96	        `${index + 1}. claimId=${claim.id}\n` +
97	        `status=${claim.status}; claimType=${claim.claimType}; claimKind=${claim.claimKind ?? 'uncertain'}; kindConfidence=${claim.claimKindConfidence ?? 'unknown'}; kindReviewStatus=${claim.claimKindReviewStatus ?? 'unreviewed'}\n` +
98	        `impact=${claim.impactScore}; confidence=${claim.confidenceScore}\n` +
99	        `summary=${claim.summary}`,
100	    )
101	    .join('\n\n');
102	}
103	
104	async function loadSupportClaims(args: {
105	  documentId?: string;
106	  sourceOutlineId?: string;
107	  claimIds?: string[];
108	  relationshipScope?: 'single_source' | 'cross_source';
109	}): Promise<{ claims: SupportClaim[]; documentId: string | null; sourceOutlineId: string | null }> {
110	  const db = getDirectDb();
111	  let documentId = args.documentId ?? null;
112	  let sourceOutlineId = args.sourceOutlineId ?? null;
113	
114	  if (sourceOutlineId && !documentId) {
115	    const [source] = await db
116	      .select({ documentId: sourceOutlineSources.documentId })
117	      .from(sourceOutlineSources)
118	      .where(
119	        and(
120	          eq(sourceOutlineSources.sourceOutlineId, sourceOutlineId),
121	          eq(sourceOutlineSources.sourceType, 'document'),
122	        ),
123	      )
124	      .limit(1);
125	    documentId = source?.documentId ?? null;
126	  }
127	
128	  let rows: SupportClaim[] = [];
129	  if (args.claimIds?.length) {
130	    rows = await db
131	      .select({
132	        id: claims.id,
133	        summary: claims.summary,
134	        claimType: claims.claimType,
135	        claimKind: claims.claimKind,
136	        claimKindConfidence: claims.claimKindConfidence,
137	        claimKindReviewStatus: claims.claimKindReviewStatus,
138	        status: claims.status,
139	        impactScore: claims.impactScore,
140	        confidenceScore: claims.confidenceScore,
141	      })
142	      .from(claims)
143	      .where(inArray(claims.id, args.claimIds))
144	      .limit(40);
145	  } else if (documentId && args.relationshipScope === 'cross_source') {
146	    const result = await db.execute(sql`
147	      WITH seed_claims AS (
148	        SELECT DISTINCT c.id
149	        FROM claims c
150	        JOIN claim_evidence ce ON ce.claim_id = c.id
151	        JOIN document_chunks dc ON dc.id = ce.source_document_chunk_id
152	        WHERE dc.document_id = ${documentId}::uuid
153	          AND c.status IN ('pending_review', 'approved')
154	      ),
155	      seed_domains AS (
156	        SELECT DISTINCT ctd.top_domain_id
157	        FROM claim_top_domains ctd
158	        JOIN seed_claims sc ON sc.id = ctd.claim_id
159	      ),
160	      related_claims AS (
161	        SELECT DISTINCT c.id
162	        FROM claims c
163	        JOIN claim_top_domains ctd ON ctd.claim_id = c.id
164	        WHERE c.status IN ('pending_review', 'approved')
165	          AND ctd.top_domain_id IN (SELECT top_domain_id FROM seed_domains)
166	      )
167	      SELECT DISTINCT
168	        c.id,
169	        c.summary,
170	        c.claim_type AS "claimType",
171	        c.claim_kind AS "claimKind",
172	        c.claim_kind_confidence AS "claimKindConfidence",
173	        c.claim_kind_review_status AS "claimKindReviewStatus",
174	        c.status,
175	        c.impact_score AS "impactScore",
176	        c.confidence_score AS "confidenceScore"
177	      FROM claims c
178	      WHERE c.id IN (
179	        SELECT id FROM seed_claims
180	        UNION
181	        SELECT id FROM related_claims
182	      )
183	      ORDER BY
184	        CASE WHEN c.id IN (SELECT id FROM seed_claims) THEN 0 ELSE 1 END,
185	        c.impact_score DESC,
186	        c.confidence_score DESC,
187	        c.created_at DESC
188	      LIMIT 40
189	    `);
190	    rows = [...result] as SupportClaim[];
191	  } else if (documentId) {
192	    const result = await db.execute(sql`
193	      SELECT DISTINCT
194	        c.id,
195	        c.summary,
196	        c.claim_type AS "claimType",
197	        c.claim_kind AS "claimKind",
198	        c.claim_kind_confidence AS "claimKindConfidence",
199	        c.claim_kind_review_status AS "claimKindReviewStatus",
200	        c.status,
201	        c.impact_score AS "impactScore",
202	        c.confidence_score AS "confidenceScore"
203	      FROM claims c
204	      JOIN claim_evidence ce ON ce.claim_id = c.id
205	      JOIN document_chunks dc ON dc.id = ce.source_document_chunk_id
206	      WHERE dc.document_id = ${documentId}::uuid
207	        AND c.status IN ('pending_review', 'approved')
208	      ORDER BY c.impact_score DESC, c.confidence_score DESC, c.created_at DESC
209	      LIMIT 40
210	    `);
211	    rows = [...result] as SupportClaim[];
212	  }
213	
214	  if (!sourceOutlineId && documentId) {
215	    const [outline] = await db
216	      .select({ id: sourceOutlines.id })
217	      .from(sourceOutlines)
218	      .innerJoin(
219	        sourceOutlineSources,
220	        eq(sourceOutlineSources.sourceOutlineId, sourceOutlines.id),
221	      )
222	      .where(
223	        and(
224	          eq(sourceOutlineSources.documentId, documentId),
225	          eq(sourceOutlineSources.sourceType, 'document'),
226	          eq(sourceOutlines.status, 'provisional'),
227	        ),
228	      )
229	      .limit(1);
230	    sourceOutlineId = outline?.id ?? null;
231	  }
232	
233	  return { claims: rows, documentId, sourceOutlineId };
234	}
