236	function settingToNumber(value: unknown, fallback: number, options: { min?: number; max?: number } = {}): number {
237	  const parsed = typeof value === 'number' ? value : Number(value ?? fallback);
238	  if (!Number.isFinite(parsed)) return fallback;
239	  const min = options.min ?? Number.NEGATIVE_INFINITY;
240	  const max = options.max ?? Number.POSITIVE_INFINITY;
241	  return Math.max(min, Math.min(max, parsed));
242	}
243	
244	function settingToStringArray(value: unknown): string[] {
245	  if (!Array.isArray(value)) return [];
246	  return value.map((entry) => String(entry).trim()).filter(Boolean);
247	}
248	
249	async function loadMacroBudget(): Promise<MacroBudget> {
250	  const db = getDirectDb();
251	  const rows = await db.execute(sql`
252	    SELECT key, value FROM settings
253	    WHERE key IN (
254	      'macro_auto_max_support_claims',
255	      'macro_relationship_near_duplicate_distance',
256	      'macro_entity_validation_extra_stopwords'
257	    )
258	  `);
259	  const map = new Map(([...rows] as Array<{ key: string; value: unknown }>).map((row) => [row.key, row.value]));
260	  return {
261	    maxSupportClaims: Math.floor(
262	      settingToNumber(map.get('macro_auto_max_support_claims'), 40, { min: 2, max: 80 }),
263	    ),
264	    nearDuplicateDistance: settingToNumber(
265	      map.get('macro_relationship_near_duplicate_distance'),
266	      DEFAULT_MACRO_RELATIONSHIP_NEAR_DUPLICATE_DISTANCE,
267	      { min: 0.001, max: 1 },
268	    ),
269	    entityValidationExtraStopwords: settingToStringArray(
270	      map.get('macro_entity_validation_extra_stopwords'),
271	    ),
272	  };
273	}
