275	async function runMacroRelationshipExtraction(rawPayload: unknown) {
276	  const payload = payloadSchema.parse(rawPayload);
277	  const db = getDirectDb();
278	  const support = await loadSupportClaims(payload);
279	  if (support.claims.length < 2) {
280	    return { status: 'skipped_too_few_claims', count: support.claims.length };
281	  }
282	  const budget = await loadMacroBudget();
283	  support.claims = support.claims.slice(0, budget.maxSupportClaims);
284	
285	  const client = new OracleAIClient({ adapters: buildStandardAdapters() });
286	  const resolved = await resolveRouteCandidates(db, 'general');
287	  const routeCandidates = resolved.candidates;
288	  const route = routeCandidates[0]!.route;
289	  const claimIds = support.claims.map((claim) => claim.id);
290	
291	  const [outline] = support.sourceOutlineId
292	    ? await db
293	        .select({ summary: sourceOutlines.summary, outlineJson: sourceOutlines.outlineJson })
294	        .from(sourceOutlines)
295	        .where(eq(sourceOutlines.id, support.sourceOutlineId))
296	        .limit(1)
297	    : [null];
298	
299	  const blocks = [
300	    makeBlock({
301	      id: 'macro-relationship-system',
302	      label: 'Macro relationship system prompt',
303	      kind: 'stable_system',
304	      content: MACRO_RELATIONSHIP_SYSTEM_PROMPT,
305	      reasonIncluded: `macro relationship prompt v${MACRO_RELATIONSHIP_PROMPT_VERSION}`,
306	    }),
307	    ...(outline
308	      ? [
309	          makeBlock({
310	            id: 'source-outline-summary',
311	            label: 'Source outline summary',
312	            kind: 'semi_stable_domain_context' as const,
313	            content: JSON.stringify({
314	              summary: outline.summary,
315	              outline: outline.outlineJson,
316	            }),
317	            reasonIncluded: 'provisional source outline guides macro grouping only',
318	          }),
319	        ]
320	      : []),
321	    makeBlock({
322	      id: 'support-claims',
323	      label: 'Candidate support claims',
324	      kind: 'retrieved_context',
325	      content: formatClaimsForPrompt(support.claims),
326	      reasonIncluded: `${support.claims.length} bounded support candidate claims`,
327	    }),
328	    makeBlock({
329	      id: 'macro-relationship-request',
330	      label: 'Macro relationship request',
331	      kind: 'dynamic_input',
332	      content:
333	        'Propose high-value macro relationships supported only by the supplied claims. Use claim IDs exactly. Omit weak or duplicate relationships.',
334	      reasonIncluded: 'request macro relationship proposals',
335	    }),
336	  ];
337	
338	  const plan = client.compile({
339	    taskType: 'macro_relationship',
340	    routeId: route.routeId,
341	    promptVersion: MACRO_RELATIONSHIP_PROMPT_VERSION,
342	    blocks,
343	    observability: { includedClaimIds: claimIds },
344	  });
345	  const [contextPack] = await db
346	    .insert(oracleContextPacks)
347	    .values(buildContextPackInsert(plan))
348	    .returning({ id: oracleContextPacks.id });
349	  if (!contextPack) throw new Error('[macro-relationship] failed to insert context pack');
350	
351	  const started = Date.now();
352	  const result = await client
353	    .runObject<MacroRelationshipOutput>({
354	      taskType: 'macro_relationship',
355	      routeId: route.routeId,
356	      promptVersion: MACRO_RELATIONSHIP_PROMPT_VERSION,
357	      blocks,
358	      schema: MacroRelationshipOutputSchema,
359	      observability: { includedClaimIds: claimIds },
360	      providerOptions: { maxOutputTokens: 12_000 },
361	      routeCandidates,
362	    })
363	    .catch(async (err) => {
364	      await logAllCandidatesFailedAttempts({
365	        db,
366	        error: err,
367	        taskType: 'macro-relationship',
368	        slot: 'general',
369	        contextPackId: contextPack.id,
370	      });
371	      throw err;
372	    });
373	
374	  const [modelRun] = await db
375	    .insert(modelRuns)
376	    .values({
377	      taskType: 'macro-relationship',
378	      model: result.modelId ?? route.modelId,
379	      provider: result.provider ?? route.provider,
380	      promptVersion: MACRO_RELATIONSHIP_PROMPT_VERSION,
381	      inputHash: plan.metadata.stablePrefixHash,
382	      inputTokens: result.usage.inputTokens ?? null,
383	      outputTokens: result.usage.outputTokens ?? null,
384	      latencyMs: Date.now() - started,
385	      success: result.validation.ok,
386	      error: result.validation.ok ? null : result.validation.error.message,
387	    })
388	    .returning({ id: modelRuns.id });
389	  if (!modelRun) throw new Error('[macro-relationship] failed to insert model run');
390	
391	  await db.insert(modelRunUsageDetails).values({
392	    modelRunId: modelRun.id,
393	    contextPackId: contextPack.id,
394	    routeId: result.routeId ?? route.routeId,
395	    inputTokens: result.usage.inputTokens ?? null,
396	    cachedInputTokens: result.usage.cachedInputTokens ?? null,
397	    cacheWriteTokens: result.usage.cacheWriteTokens ?? null,
398	    outputTokens: result.usage.outputTokens ?? null,
399	    reasoningTokens: result.usage.reasoningTokens ?? null,
400	    providerRequestId: result.usage.providerRequestId ?? null,
401	    rawUsageJson: result.usage.rawUsageJson ?? null,
402	  });
403	  await logModelRunAttempts({
404	    db,
405	    metadata: result,
406	    taskType: 'macro-relationship',
407	    slot: 'general',
408	    contextPackId: contextPack.id,
409	    modelRunId: modelRun.id,
410	  });
411	  await db
412	    .update(oracleContextPacks)
413	    .set({ modelRunId: modelRun.id })
414	    .where(eq(oracleContextPacks.id, contextPack.id));
415	
416	  if (!result.validation.ok) {
417	    throw new Error(
418	      '[macro-relationship] model output failed Zod schema validation: ' +
419	        result.validation.error.message,
420	    );
421	  }
422	
423	  const supportById = new Map(support.claims.map((claim) => [claim.id, claim]));
424	  const registryRows = await db.select({ canonicalValue: entities.canonicalValue }).from(entities);
425	  const registryEntityNames = registryRows.map((row) => row.canonicalValue);
426	  let inserted = 0;
427	  let rejectedUnsupportedEntities = 0;
428	  let rejectedNearDuplicates = 0;
429	  for (const relationship of result.object.relationships) {
430	    const supportLinks = relationship.supportingClaims.filter((link) => supportById.has(link.claimId));
431	    if (supportLinks.length < 2) continue;
432	    const entityValidation = validateMacroRelationshipSummaryEntities({
433	      summary: relationship.summary,
434	      supportClaimSummaries: supportLinks.map((link) => supportById.get(link.claimId)!.summary),
435	      registryEntityNames,
436	      extraStopwords: budget.entityValidationExtraStopwords,
437	    });
438	    if (!entityValidation.ok) {
439	      rejectedUnsupportedEntities += 1;
440	      console.warn('[macro-relationship] rejected unsupported summary entities', {
441	        unsupportedEntities: entityValidation.unsupportedEntities,
442	        summary: relationship.summary,
443	      });
444	      continue;
445	    }
446	
447	    const duplicateHash = sha256(
448	      `${relationship.relationshipType}\n${relationship.summary.toLowerCase().replace(/\s+/g, ' ').trim()}\n${supportLinks.map((link) => link.claimId).sort().join(',')}`,
449	    );
450	    const [existing] = await db
451	      .select({ id: macroRelationships.id })
452	      .from(macroRelationships)
453	      .where(sql`metadata_json->>'dedupeHash' = ${duplicateHash}`)
454	      .limit(1);
455	    if (existing) continue;
456	
457	    const { vector } = await embedText(relationship.summary);
458	    const vec = `[${vector.join(',')}]`;
459	    const [nearDuplicate] = await db.execute<{ id: string; status: string; distance: number }>(sql`
460	      SELECT id, status, embedding <=> ${vec}::vector(${sql.raw(String(EMBEDDING_DIM))}) AS distance
461	      FROM macro_relationships
462	      WHERE relationship_type = ${relationship.relationshipType}
463	        AND status IN ('pending_review', 'blocked_pending_support', 'needs_review', 'approved', 'rejected')
464	        AND embedding IS NOT NULL
465	        AND embedding <=> ${vec}::vector(${sql.raw(String(EMBEDDING_DIM))}) < ${budget.nearDuplicateDistance}
466	      ORDER BY embedding <=> ${vec}::vector(${sql.raw(String(EMBEDDING_DIM))})
467	      LIMIT 1
468	    `);
469	    if (nearDuplicate) {
470	      if (nearDuplicate.status === 'rejected') rejectedNearDuplicates += 1;
471	      continue;
472	    }
473	
474	    const supportStatuses = supportLinks.map((link) => supportById.get(link.claimId)?.status ?? 'missing');
475	    const [row] = await db
476	      .insert(macroRelationships)
477	      .values({
478	        relationshipType: relationship.relationshipType,
479	        summary: relationship.summary,
480	        status: statusForGeneratedMacroRelationship(supportStatuses),
481	        sourceOutlineId: support.sourceOutlineId,
482	        confidenceScore: relationship.confidenceScore,
483	        impactScore: relationship.impactScore,
484	        triageScore: String(relationship.impactScore * 10 + relationship.confidenceScore),
485	        embedding: vector,
486	        metadataJson: {
487	          whyThisIsMacro: relationship.whyThisIsMacro,
488	          reviewReason: relationship.reviewReason ?? null,
489	          riskFlags: relationship.riskFlags ?? [],
490	          sourceOutlineElementIds: relationship.sourceOutlineElementIds ?? [],
491	          dedupeHash: duplicateHash,
492	        },
493	        modelRunId: modelRun.id,
494	        contextPackId: contextPack.id,
495	      })
496	      .returning({ id: macroRelationships.id });
497	    if (!row) continue;
498	
499	    await db.insert(macroRelationshipClaims).values(
500	      supportLinks.map((link, index) => {
501	        const supportClaim = supportById.get(link.claimId)!;
502	        return {
503	          macroRelationshipId: row.id,
504	          claimId: link.claimId,
505	          supportRole: link.supportRole,
506	          claimStatusAtLink: supportClaim.status,
507	          claimVersionHash: sha256(supportClaim.summary),
508	          sortOrder: index,
509	        };
510	      }),
511	    );
512	
513	    if (support.documentId) {
514	      await db.insert(macroRelationshipSources).values({
515	        macroRelationshipId: row.id,
516	        sourceType: 'document',
517	        documentId: support.documentId,
518	      });
519	    }
520	
521	    if (relationship.relationshipType === 'contradiction_or_tension' && supportLinks.length >= 2) {
522	      await db.insert(contradictions).values({
523	        claimAId: supportLinks[0]!.claimId,
524	        claimBId: supportLinks[1]!.claimId,
525	        description: relationship.summary,
526	        severity: relationship.impactScore >= 8 ? 'high' : 'medium',
527	        status: 'possible',
528	        detectionConfidence: relationship.confidenceScore * 10,
529	        retrievedClaimIds: supportLinks.map((link) => link.claimId),
530	        createdByModelRunId: modelRun.id,
531	      });
532	    }
533	
534	    inserted += 1;
535	  }
536	
537	  return { status: 'complete', inserted, rejectedUnsupportedEntities, rejectedNearDuplicates };
538	}
