1	import { eq, inArray } from 'drizzle-orm';
2	import type { OracleDb } from '@oracle/db';
3	import { modelCapabilities, settings } from '@oracle/db/schema';
4	import { getAuxiliaryModelDef } from './auxiliary';
5	import {
6	  ENFORCE_MODEL_CAPABILITIES_SETTING_KEY,
7	  MODEL_POOL_SETTING_KEYS,
8	  REASONING_EFFORT_SETTING_KEYS,
9	  ROUTE_SETTING_KEYS,
10	} from './defaults';
11	import { ModelCapabilityError, NoConfiguredModelError, type ModelSlot } from './errors';
12	import { missingRequirements } from './capability-requirements';
13	import { providerModelIdForRoute, resolveModelRoute, type SyntheticRouteCaps } from './resolve';
14	import type { ModelCapability } from '../model-capabilities/types';
15	import type { OracleModelRole, OracleModelRoute, ReasoningEffort } from './types';
16	
17	export interface RouteCandidate {
18	  route: OracleModelRoute;
19	  slot: ModelSlot;
20	  isPrimary: boolean;
21	  approvedModelId: string;
22	}
23	
24	export interface SkippedRouteCandidate {
25	  slot: ModelSlot;
26	  modelIdOrRouteId: string;
27	  reason: string;
28	}
29	
30	export interface RouteCandidateResolution {
31	  slot: ModelSlot;
32	  candidates: RouteCandidate[];
33	  skipped: SkippedRouteCandidate[];
34	}
35	
36	function isReasoningEffort(v: unknown): v is ReasoningEffort {
37	  return v === 'off' || v === 'low' || v === 'medium' || v === 'high';
38	}
39	
40	function isPipelineSlot(slot: ModelSlot): slot is OracleModelRole {
41	  return slot === 'interview' || slot === 'extraction' || slot === 'synthesis';
42	}
43	
44	function roleForSlot(slot: ModelSlot): OracleModelRole {
45	  return isPipelineSlot(slot) ? slot : 'extraction';
46	}
47	
48	function settingKeysForSlot(slot: ModelSlot): {
49	  routeKey: string;
50	  effortKey?: string;
51	  poolKey?: string;
52	} {
53	  if (isPipelineSlot(slot)) {
54	    return {
55	      routeKey: ROUTE_SETTING_KEYS[slot],
56	      effortKey: REASONING_EFFORT_SETTING_KEYS[slot],
57	      poolKey: MODEL_POOL_SETTING_KEYS[slot],
58	    };
59	  }
60	  const def = getAuxiliaryModelDef(slot);
61	  if (!def) throw new NoConfiguredModelError(slot, 'unknown auxiliary model id');
62	  return {
63	    routeKey: def.routeSettingKey,
64	    effortKey: def.reasoningEffortSettingKey,
65	  };
66	}
67	
68	function capToRouteCaps(cap: ModelCapability): SyntheticRouteCaps {
69	  const normalized = normalizeProviderCapabilities(cap);
