// One-off: apply specific hand-written idempotent SQL migrations to prod via the
// session pooler. Lives in .cache/ (gitignored) so it resolves the repo's pg dep
// and is not tracked. Reads PROD_DB_URL from env (never logged).
import { readFileSync } from 'node:fs';
import pg from 'pg';

const url = process.env.PROD_DB_URL;
if (!url) {
  console.error('PROD_DB_URL not set');
  process.exit(1);
}
const files = process.argv.slice(2);
if (files.length === 0) {
  console.error('no migration files given');
  process.exit(1);
}

const client = new pg.Client({ connectionString: url, ssl: { rejectUnauthorized: false } });
await client.connect();
try {
  for (const f of files) {
    const sql = readFileSync(f, 'utf8');
    process.stdout.write(`Applying ${f} ... `);
    await client.query(sql);
    console.log('OK');
  }
} catch (err) {
  console.error('FAILED:', err.message);
  process.exitCode = 1;
} finally {
  await client.end();
}

