1	// Source outline worker: creates provisional macro context for a document.
2	//
3	// Outlines are guidance only. They are not claim evidence, never promote
4	// claims, and can only reference persisted document chunks for inspectability.
5	
6	import { task, tasks } from '@trigger.dev/sdk/v3';
7	import { and, desc, eq, inArray } from 'drizzle-orm';
8	import { createHash } from 'node:crypto';
9	import { z } from 'zod';
10	import {
11	  OracleAIClient,
12	  SOURCE_OUTLINE_PROMPT_VERSION,
13	  SOURCE_OUTLINE_SYSTEM_PROMPT,
14	  SourceOutlineSchema,
15	  buildStandardAdapters,
16	  embedMany,
17	  logAllCandidatesFailedAttempts,
18	  logModelRunAttempts,
19	  makeBlock,
20	  resolveRouteCandidates,
21	  type OraclePromptPlan,
22	  type SourceOutlineOutput,
23	} from '@oracle/ai';
24	import { getDirectDb } from '@oracle/db/client';
25	import {
26	  documentChunks,
27	  documents,
28	  jobRuns,
29	  modelRunUsageDetails,
30	  modelRuns,
31	  oracleContextPacks,
32	  sourceGroupItems,
33	  sourceGroups,
