39	import { buildLensDispatchPlan } from '../lib/document-lens-budget';
40	import { markMacroFailed, markMacroPending } from '../lib/macro-health';
41	import { triggerMacroFollowupsOnce } from '../lib/macro-followups';
42	
43	const payloadSchema = z.object({
44	  documentId: z.string().uuid(),
45	  force: z.boolean().optional(),
46	});
47	
48	type ChunkRow = {
49	  id: string;
50	  chunkIndex: number;
51	  pageNumber: number | null;
52	  rawText: string;
53	  contentHash: string | null;
54	};
55	
56	function sha256(text: string): string {
57	  return createHash('sha256').update(text, 'utf8').digest('hex');
58	}
59	
60	function buildContextPackInsert(plan: OraclePromptPlan) {
61	  return {
62	    taskType: plan.taskType,
63	    routeId: plan.routeId,
64	    promptVersion: plan.promptVersion,
65	    schemaVersion: plan.schemaVersion ?? null,
66	    stablePrefixHash: plan.metadata.stablePrefixHash,
67	    semiStableContextHash: plan.metadata.semiStableContextHash ?? null,
68	    retrievedContextHash: plan.metadata.retrievedContextHash ?? null,
69	    dynamicInputHash: plan.metadata.dynamicInputHash,
70	    toolSchemaHash: plan.metadata.toolSchemaHash ?? null,
71	    outputSchemaHash: plan.metadata.outputSchemaHash ?? null,
72	    blocksJson: plan.blocks.map((b) => ({
73	      id: b.id,
74	      label: b.label,
75	      kind: b.kind,
76	      hash: b.hash,
77	      tokenEstimate: b.tokenEstimate ?? null,
78	      cacheEligible: b.cacheEligible,
79	      reasonIncluded: b.reasonIncluded,
80	    })),
81	    includedDocumentChunkIds: plan.metadata.includedDocumentChunkIds ?? null,
82	  };
83	}
84	
85	function buildDocumentCorpus(chunks: ChunkRow[]): string {
86	  return chunks
87	    .map((chunk) => {
88	      const page = chunk.pageNumber ? ` page=${chunk.pageNumber}` : '';
89	      return `--- Document Chunk ID: ${chunk.id} index=${chunk.chunkIndex}${page} ---\n${chunk.rawText}`;
90	    })
91	    .join('\n\n');
92	}
93	
94	function normalizeOutlineRefs(
95	  outline: SourceOutlineOutput,
96	  chunkIds: Set<string>,
97	): SourceOutlineOutput {
98	  const validRefs = outline.refs.filter((ref) => chunkIds.has(ref.chunkId));
99	  const groups = outline.groups
100	    .map((group) => ({
101	      ...group,
102	      chunkIds: Array.from(new Set(group.chunkIds.filter((id) => chunkIds.has(id)))),
103	    }))
104	    .filter((group) => group.chunkIds.length > 0);
105	
106	  return {
107	    ...outline,
108	    refs: validRefs,
109	    groups,
110	    entities: outline.entities.map((entity) => ({
111	      ...entity,
112	      chunkIds: entity.chunkIds?.filter((id) => chunkIds.has(id)),
113	    })),
114	    terms: outline.terms.map((term) => ({
115	      ...term,
116	      chunkIds: term.chunkIds?.filter((id) => chunkIds.has(id)),
117	    })),
118	    stages: outline.stages.map((stage) => ({
119	      ...stage,
120	      chunkIds: stage.chunkIds?.filter((id) => chunkIds.has(id)),
121	    })),
122	  };
123	}
124	
125	async function supersedeExistingDocumentOutlines(db: OracleDb, documentId: string): Promise<void> {
126	  const existing = await db
127	    .select({ outlineId: sourceOutlineSources.sourceOutlineId })
128	    .from(sourceOutlineSources)
129	    .where(
130	      and(
131	        eq(sourceOutlineSources.sourceType, 'document'),
132	        eq(sourceOutlineSources.documentId, documentId),
133	      ),
134	    );
135	
136	  const ids = Array.from(new Set(existing.map((row) => row.outlineId)));
137	  if (ids.length === 0) return;
138	
139	  await db
140	    .update(sourceOutlines)
141	    .set({ status: 'superseded', updatedAt: new Date() })
142	    .where(and(inArray(sourceOutlines.id, ids), eq(sourceOutlines.status, 'provisional')));
143	}
144	
145	async function persistOutline(args: {
146	  db: OracleDb;
147	  documentId: string;
148	  sourceHash: string;
149	  outline: SourceOutlineOutput;
150	  modelRunId: string | null;
151	  contextPackId: string | null;
152	}): Promise<string> {
153	  const { db, documentId, sourceHash, outline, modelRunId, contextPackId } = args;
154	
155	  await supersedeExistingDocumentOutlines(db, documentId);
156	
157	  const groupTexts = outline.groups.map((group) =>
158	    [group.title, group.description, group.recommendedLenses?.join(', ')]
159	      .filter(Boolean)
160	      .join('\n'),
161	  );
162	  let groupEmbeddings: number[][] = [];
163	  if (groupTexts.length > 0) {
164	    try {
165	      groupEmbeddings = (await embedMany(groupTexts)).vectors;
166	    } catch (err) {
167	      console.warn('[source-outline] group embedding failed; storing groups without vectors', err);
168	      groupEmbeddings = [];
169	    }
170	  }
171	
172	  const [outlineRow] = await db
173	    .insert(sourceOutlines)
174	    .values({
175	      sourceType: 'document',
176	      status: 'provisional',
177	      outlineVersion: SOURCE_OUTLINE_PROMPT_VERSION,
178	      modelRunId,
179	      contextPackId,
180	      sourceHash,
181	      outlineJson: outline,
182	      summary: outline.summary,
183	      budgetJson: outline.budget,
184	    })
185	    .returning({ id: sourceOutlines.id });
186	  if (!outlineRow) throw new Error('[source-outline] failed to insert source_outlines row');
187	
188	  await db.insert(sourceOutlineSources).values({
189	    sourceOutlineId: outlineRow.id,
190	    sourceType: 'document',
191	    documentId,
192	    sourceHash,
193	  });
194	
195	  const refRows = outline.refs.map((ref) => ({
196	    sourceOutlineId: outlineRow.id,
197	    outlineElementId: null,
198	    refType: 'document_chunk',
199	    documentChunkId: ref.chunkId,
200	    refRole: ref.role,
201	    metadataJson: ref.note ? { note: ref.note } : null,
202	  }));
203	  if (refRows.length > 0) {
204	    await db.insert(sourceOutlineSourceRefs).values(refRows);
205	  }
206	
207	  for (let i = 0; i < outline.groups.length; i++) {
208	    const group = outline.groups[i]!;
209	    const [groupRow] = await db
